mapper.select:
SELECT FROM sys_user
AND username != 'admin'
AND (username ILIKE '%' || #{keyword} || '%' OR nickname ILIKE '%' || #{keyword} || '%' OR email ILIKE '%' || #{keyword} || '%')
AND status = #{status}
ORDER BY create_time DESC LIMIT #{size} OFFSET #{offset}

