nickname = #{nickname}, email = #{email}, phone = #{phone}, remark = #{remark}, status = #{status}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE sys_user
SET password = #{password}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}

