WHERE id = #{id}

UPDATE sys_user
SET roles = #{roles}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE sys_user
SET last_login_time = CURRENT_TIMESTAMP
WHERE id = #{id}

